class Solution {
    public int maxValue(int n, int index, int maxSum) {
        int[] nums = new int[n];
        Arrays.fill(nums, 0);
        int sum = 0;
        int currSum = 0;
        int maxValue = Integer.MIN_VALUE;

        for (int i = 0; i < n; i++) {
            nums[i] = i + 1;
            sum += nums[i];
            currSum += nums[i];
            if (sum > maxValue && currSum <= maxSum) {
                maxValue = sum;
            }
            if (i == index) {
                nums[i] = max(nums[i], nums[i - 1]);
            }
        }

        return maxValue;
    }
}
```

